function solve(nums: number[]): number {
    let maxSum = 0;
    const n = nums.length;

    // Generate all possible subsets for B (can be empty)
    for (let maskB = 0; maskB < (1 << n); maskB++) {
        let andB = 0xFFFFFFFF;
        let hasB = false;
        for (let i = 0; i < n; i++) {
            if (maskB & (1 << i)) {
                andB &= nums[i];
                hasB = true;
            }
        }
        if (!hasB) {
            andB = 0;
        }

        // Remaining elements are not in B
        const remaining: number[] = [];
        for (let i = 0; i < n; i++) {
            if (!(maskB & (1 << i))) {
                remaining.push(nums[i]);
            }
        }
        const m = remaining.length;

        // Generate all possible subsets for A (can be empty)
        for (let maskA = 0; maskA < (1 << m); maskA++) {
            let xorA = 0;
            for (let i = 0; i < m; i++) {
                if (maskA & (1 << i)) {
                    xorA ^= remaining[i];
                }
            }

            // C is the rest in remaining
            let xorC = 0;
            for (let i = 0; i < m; i++) {
                if (!(maskA & (1 << i))) {
                    xorC ^= remaining[i];
                }
            }

            const currentSum = xorA + andB + xorC;
            if (currentSum > maxSum) {
                maxSum = currentSum;
            }
        }
    }

    return maxSum;
}
